// ============================================================
// JSONKB v1 — SYSTEMS
// IMPORTANT: Explicitly read from specific upstream nodes
// to avoid "items[0]" pointing at the wrong input.
// ============================================================

// Pull the system detail row from the named node
const sysItems = $items("System – Detail");
if (!sysItems || sysItems.length === 0) {
  throw new Error('JSONKB Systems: Missing input from node "System – Detail".');
}
const sys = sysItems[0].json;


// ---------- Parse bodies list ----------
let bodies = [];
if (Array.isArray(sys.bodies_list)) {
  bodies = sys.bodies_list;
} else if (typeof sys.bodies_list === 'string') {
  try { bodies = JSON.parse(sys.bodies_list); } catch (e) { bodies = []; }
} else if (sys.bodies_list && typeof sys.bodies_list === 'object') {
  bodies = Object.values(sys.bodies_list);
}

bodies = (bodies || [])
  .map(b => String(b || '').trim())
  .filter(b => b.length > 0)
  .sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

const bodiesTotal = Number(sys.bodies_total ?? bodies.length) || 0;

// ---------- Parse major locations list ----------
let majorLocations = [];
if (Array.isArray(sys.major_locations_list)) {
  majorLocations = sys.major_locations_list;
} else if (typeof sys.major_locations_list === 'string') {
  try { majorLocations = JSON.parse(sys.major_locations_list); } catch (e) { majorLocations = []; }
} else if (sys.major_locations_list && typeof sys.major_locations_list === 'object') {
  majorLocations = Object.values(sys.major_locations_list);
}

majorLocations = (majorLocations || [])
  .map(l => String(l || '').trim())
  .filter(l => l.length > 0)
  .sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

const mlocsTotal = Number(sys.major_locations_total ?? majorLocations.length) || 0;

// ---------- Slug ----------
const slug = String(sys.slug || sys.name || '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

if (!slug) {
  throw new Error('JSONKB Systems: slug is empty (cannot write JSONKB file).');
}

// ---------- Deterministic kb_text ----------
const systemName = sys.name || 'Unknown System';
const isLive = String(sys.is_available_live) === '1' || sys.is_available_live === 1;

const statusLabel = isLive ? 'live' : 'planned or inactive';

// Keep trade sentence as-is for now (you can gate later if you add a has_prices flag)
const kb_text =
  `${systemName} is a star system containing ${bodiesTotal} planetary bodies and ${mlocsTotal} locations. ` +
  `This system is ${statusLabel}.`;

// ---------- entity_metadata ----------
const entity_metadata = {
  uex_system_id: sys.uex_system_id != null ? Number(sys.uex_system_id) : null,
  system_code: sys.system_code || null,
  status: statusLabel,
  body_count: bodiesTotal,
  major_location_count: mlocsTotal,
  bodies,
  major_locations: majorLocations,
};


const kb_links = {
  kb_page_path: `/kb/${slug}`,
  kb_browse_path: `/browse?category=system`,
};

// ---------- rag_hints (stub) ----------
const rag_hints = {
  sql_hints: [
    {
      id: "system.planets",
      description: "List planet bodies in a system.",
      params: [{"name":"system_id","type":"uuid","required":true}],
      sql_template: `SELECT b.id, b.name, b.slug
FROM bodies b
WHERE b.system_id = :system_id
  AND lower(b.body_type) = 'planet'
ORDER BY b.name;`
    },
    {
      id: "system.moons",
      description: "List moon bodies in a system.",
      params: [{"name":"system_id","type":"uuid","required":true}],
      sql_template: `SELECT b.id, b.name, b.slug, b.parent_body_id
FROM bodies b
WHERE b.system_id = :system_id
  AND lower(b.body_type) = 'moon'
ORDER BY b.name;`
    },
  ],
  notes: null
};

// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Systems v1',
  game_version: sys.game_version || null,
  is_live_only: true,
};

// ---------- JSONKB object ----------
const jsonkb = {
  kb_version: '1.0',

  entity_type: 'system',
  entity_id: sys.id || null,
  entity_slug: slug,
  entity_name: systemName,

  source: sys.source || 'uex',
  source_id: sys.source_id || (sys.uex_system_id != null ? `star_systems:${sys.uex_system_id}` : null),
  source_table: 'systems',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

function stableStringify(value) {
  const seen = new WeakSet();

  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null; // defensive; shouldn’t happen
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm); // keep array order

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }

    return v;
  }

  return JSON.stringify(norm(value));
}

// ---------- hash (FNV32 doubled => 16 hex chars) ----------
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);

// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/system/${slug}`;

return [
  {
    json: {
      system_id: sys.id,
      slug,
      name: systemName,
      jsonkb,
      jsonkb_file_path,
    },
  },
];

